59	static S2N_RESULT s2n_check_ecdhe(const struct s2n_cipher_suite *cipher_suite, struct s2n_connection *conn, bool *is_supported)
60	{
61	    RESULT_ENSURE_REF(cipher_suite);
62	    RESULT_ENSURE_REF(conn);
63	    RESULT_ENSURE_REF(is_supported);
64	
65	    *is_supported = conn->kex_params.server_ecc_evp_params.negotiated_curve != NULL;
66	
67	    return S2N_RESULT_OK;
68	}
