101	static int try_handshake(struct s2n_connection *server_conn, struct s2n_connection *client_conn)
102	{
103	    s2n_blocked_status server_blocked;
104	    s2n_blocked_status client_blocked;
105	
106	    int tries = 0;
107	    do {
108	        int client_rc = s2n_negotiate(client_conn, &client_blocked);
109	        if (!(client_rc == 0 || (client_blocked && s2n_error_get_type(s2n_errno) == S2N_ERR_T_BLOCKED))) {
110	            return -1;
111	        }
112	
113	        int server_rc = s2n_negotiate(server_conn, &server_blocked);
114	        if (!(server_rc == 0 || (server_blocked && s2n_error_get_type(s2n_errno) == S2N_ERR_T_BLOCKED))) {
115	            return -1;
116	        }
117	
118	        if (server_blocked == S2N_BLOCKED_ON_APPLICATION_INPUT) {
119	            /* Only can happen in async tests */
120	            EXPECT_EQUAL(test_type, TEST_TYPE_ASYNC);
121	            EXPECT_SUCCESS(handle_async(server_conn));
122	        }
123	
124	        EXPECT_NOT_EQUAL(++tries, 5);
125	    } while (client_blocked || server_blocked);
126	
127	    POSIX_GUARD(s2n_shutdown_test_server_and_client(server_conn, client_conn));
128	    return S2N_SUCCESS;
