135	    EXPECT_NOT_NULL(security_policy);
136	
137	    if (s2n_is_in_fips_mode()) {
138	        /* Override default client config ciphers when in FIPS mode to ensure all FIPS
139	         * default ciphers are tested.
140	         */
141	        client_config->security_policy = security_policy;
142	    }
143	
144	    const struct s2n_cipher_preferences *cipher_preferences = security_policy->cipher_preferences;
145	    EXPECT_NOT_NULL(cipher_preferences);
146	
147	    /* Verify that a handshake succeeds for every available cipher in the default list. */
148	    for (int cipher_idx = 0; cipher_idx < cipher_preferences->count; cipher_idx++) {
149	        struct s2n_cipher_suite *expected_cipher = cipher_preferences->suites[cipher_idx];
150	        uint8_t expect_failure = 0;
151	
152	        /* Expect failure if the libcrypto we're building with can't support the cipher */
153	        if (!expected_cipher->available) {
154	            expect_failure = 1;
155	        }
156	
157	        TEST_DEBUG_PRINT("Testing %s in %s mode, expect_failure=%d\n", expected_cipher->name,
158	                test_type == TEST_TYPE_SYNC ? "synchronous" : "asynchronous", expect_failure);
159	
160	        struct s2n_security_policy server_security_policy;
161	        struct s2n_cipher_preferences server_cipher_preferences;
162	        struct s2n_connection *client_conn = s2n_connection_new(S2N_CLIENT);
163	        struct s2n_connection *server_conn = s2n_connection_new(S2N_SERVER);
164	        EXPECT_NOT_NULL(client_conn);
165	        EXPECT_NOT_NULL(server_conn);
166	
167	        /* Craft a cipher preference with a cipher_idx cipher and assign it to server */
168	        EXPECT_MEMCPY_SUCCESS(&server_cipher_preferences, cipher_preferences, sizeof(server_cipher_preferences));
169	        server_cipher_preferences.count = 1;
170	        server_cipher_preferences.suites = &expected_cipher;
171	
172	        EXPECT_MEMCPY_SUCCESS(&server_security_policy, security_policy, sizeof(server_security_policy));
173	        server_security_policy.cipher_preferences = &server_cipher_preferences;
174	
175	        server_conn->security_policy_override = &server_security_policy;
176	
177	        /* Create nonblocking pipes */
178	        struct s2n_test_io_pair io_pair;
179	        EXPECT_SUCCESS(s2n_io_pair_init_non_blocking(&io_pair));
180	
181	        EXPECT_SUCCESS(s2n_connection_set_io_pair(client_conn, &io_pair));
182	        EXPECT_SUCCESS(s2n_connection_set_config(client_conn, client_config));
183	
184	        EXPECT_SUCCESS(s2n_connection_set_io_pair(server_conn, &io_pair));
185	        EXPECT_SUCCESS(s2n_connection_set_config(server_conn, server_config));
186	
187	        /* Reset counters */
188	        async_pkey_op_called = 0;
189	        async_pkey_op_performed = 0;
190	
191	        if (!expect_failure) {
192	            POSIX_GUARD(try_handshake(server_conn, client_conn));
193	
194	            EXPECT_STRING_EQUAL(s2n_connection_get_cipher(server_conn), expected_cipher->name);
195	
