        /* Test: no schemes offered by the peer */
        {
            const struct s2n_signature_scheme *ecdsa_not_default = &s2n_ecdsa_sha384;
            const struct s2n_signature_scheme *rsa_not_default = &s2n_rsa_pkcs1_sha256;

