            {
                /* We should need to skip valid non-default schemes to choose the defaults */
                const struct s2n_signature_scheme *local_schemes[] = {
                    &s2n_ecdsa_sha224,
                    rsa_default,
                    ecdsa_default,
                    ecdsa_not_default
